#!/usr/bin/env python3
"""Static link checker for the azul.rs site.

The site is generated by `azul-doc deploy` into `doc/target/deploy/` and served
at https://azul.rs (the docs live under /ui/, the marketing landing at the
root). This checker finds broken *internal* links the generator emits — the
class of bug introduced by the May 2026 "move everything under /ui" change,
where hrefs kept pointing at the old `/` namespace and now 404.

Two modes:

  # Local: resolve every internal href against the generated file tree.
  #   - clean URL  /ui/guide      -> ui/guide.html  (or ui/guide/index.html)
  #   - extension  /ui/guide.html -> ui/guide.html
  #   - dir slash  /ui/           -> ui/index.html
  python scripts/check_links.py doc/target/deploy

  # Live: crawl the deployed site over HTTP and report non-2xx internal links.
  python scripts/check_links.py --live https://azul.rs

Exit code is non-zero if any broken internal link is found, so CI can gate on
it. External links (other hosts) are listed but never fail the run.
"""

import argparse
import os
import sys
from html.parser import HTMLParser
from urllib.parse import urljoin, urlparse, urldefrag

SITE_ORIGINS = ("https://azul.rs", "http://azul.rs")

# Attributes that carry a URL we care about, per tag.
URL_ATTRS = {
    "a": "href",
    "link": "href",
    "img": "src",
    "script": "src",
    "source": "src",
    "iframe": "src",
}


class LinkExtractor(HTMLParser):
    """Collect (tag, url) pairs from one HTML document."""

    def __init__(self):
        super().__init__(convert_charrefs=True)
        self.links = []

    def handle_starttag(self, tag, attrs):
        attr = URL_ATTRS.get(tag)
        if not attr:
            return
        for name, value in attrs:
            if name == attr and value:
                self.links.append((tag, value.strip()))


def is_internal(url):
    """True for links that should resolve within our own site."""
    if url.startswith(("mailto:", "tel:", "javascript:", "data:", "#")):
        return False
    parsed = urlparse(url)
    if parsed.scheme in ("http", "https"):
        return f"{parsed.scheme}://{parsed.netloc}" in SITE_ORIGINS
    # scheme-relative //azul.rs/...
    if url.startswith("//"):
        return any(url.startswith("//" + o.split("://", 1)[1]) for o in SITE_ORIGINS)
    # root-relative or document-relative paths are internal
    return parsed.scheme == ""


def is_release_asset(path):
    """True for a per-release *binary/asset* path (not an .html page).

    Release binaries (`.dll`, `.so`, `.a`, demo apps, `examples.zip`, generated
    `statistics/*`, ...) are uploaded by CI into `release/<version>/` *after* the
    website skeleton is generated, so they are legitimately absent from a local
    `azul-doc deploy` tree. They are reported separately and don't gate the exit
    code — the /ui-move breakage this checker targets is broken *page* links.
    """
    segs = [s for s in path.split("/") if s]
    if "release" not in segs:
        return False
    # Everything *inside* release/<version>/ is a CI-uploaded artifact (binaries,
    # bindings, generated statistics/*.html, ...). The release *page* itself lives
    # one level up at release/<version>.html and is NOT an asset.
    i = segs.index("release")
    return i + 2 < len(segs)


def site_path(url):
    """Reduce an internal URL to its site-absolute path (leading '/')."""
    if url.startswith(SITE_ORIGINS):
        return urlparse(url).path or "/"
    parsed = urlparse(url)
    if parsed.netloc:  # scheme-relative //azul.rs/x
        return parsed.path or "/"
    return parsed.path


def candidate_files(root, path):
    """Local files any of which satisfies a request for `path`.

    Mirrors how a static host (GitHub Pages) resolves clean URLs: `/ui/guide`
    is served by `ui/guide.html`; `/ui/` by `ui/index.html`.
    """
    rel = path.lstrip("/")
    cands = []
    if path.endswith("/") or rel == "":
        cands.append(os.path.join(root, rel, "index.html"))
    else:
        cands.append(os.path.join(root, rel))            # exact file (e.g. .html, .css, .h)
        cands.append(os.path.join(root, rel + ".html"))  # clean URL -> file.html
        cands.append(os.path.join(root, rel, "index.html"))  # clean URL -> dir/index.html
    return cands


def check_local(root):
    html_files = []
    for dirpath, _dirs, files in os.walk(root):
        for f in files:
            if f.endswith(".html"):
                html_files.append(os.path.join(dirpath, f))

    if not html_files:
        print(f"error: no .html files under {root!r} — run `azul-doc deploy` first",
              file=sys.stderr)
        return 2

    broken = []   # (source_file, raw_url, resolved_path)
    checked = 0
    for src in html_files:
        with open(src, "r", encoding="utf-8", errors="replace") as fh:
            parser = LinkExtractor()
            parser.feed(fh.read())
        src_rel = "/" + os.path.relpath(src, root).replace(os.sep, "/")
        for _tag, raw in parser.links:
            raw, _frag = urldefrag(raw)
            if not raw or not is_internal(raw):
                continue
            checked += 1
            path = site_path(raw)
            # Resolve document-relative paths against the source file's URL.
            if not path.startswith("/"):
                path = urlparse(urljoin(src_rel, raw)).path
            if not any(os.path.isfile(c) for c in candidate_files(root, path)):
                broken.append((src_rel, raw, path))

    page_broken = [b for b in broken if not is_release_asset(b[2])]
    asset_broken = [b for b in broken if is_release_asset(b[2])]
    report_broken(page_broken, asset_broken, checked, len(html_files))
    return 1 if page_broken else 0


def check_live(base):
    import urllib.request
    import urllib.error
    from collections import deque

    base = base.rstrip("/")
    seen = set()
    queue = deque(["/ui/", "/"])
    broken = []     # (path, status)
    visited_pages = 0

    def fetch(path):
        req = urllib.request.Request(base + path, method="GET",
                                     headers={"User-Agent": "azul-link-checker"})
        try:
            with urllib.request.urlopen(req, timeout=20) as resp:
                return resp.status, resp.read().decode("utf-8", "replace"), resp.headers
        except urllib.error.HTTPError as e:
            return e.code, "", {}
        except Exception as e:  # noqa: BLE001 — network errors are "broken" for our purpose
            return None, str(e), {}

    while queue:
        path = queue.popleft()
        if path in seen:
            continue
        seen.add(path)
        status, body, headers = fetch(path)
        visited_pages += 1
        if status is None or status >= 400:
            broken.append((path, status))
            continue
        ctype = headers.get("Content-Type", "") if headers else ""
        if "text/html" not in ctype:
            continue
        parser = LinkExtractor()
        parser.feed(body)
        for _tag, raw in parser.links:
            raw, _frag = urldefrag(raw)
            if not raw or not is_internal(raw):
                continue
            p = site_path(raw)
            if not p.startswith("/"):
                p = urlparse(urljoin(path, raw)).path
            if p not in seen:
                queue.append(p)

    print(f"\nCrawled {visited_pages} live URLs under {base}")
    uniq = sorted(set(broken))
    page_bad = [(p, s) for p, s in uniq if not is_release_asset(p)]
    asset_bad = [(p, s) for p, s in uniq if is_release_asset(p)]
    if asset_bad:
        print(f"\n{len(asset_bad)} release-asset URL(s) returning non-2xx "
              "(may be an arch CI didn't build — not a page bug):")
        for path, status in asset_bad:
            print(f"    [{status}] {base}{path}")
    if page_bad:
        print(f"\n{len(page_bad)} broken page/doc URL(s):")
        for path, status in page_bad:
            print(f"  BROKEN [{status}] {base}{path}")
    else:
        print("\nOK — all page/doc URLs resolve.")
    print(f"\n{len(page_bad)} page / {len(asset_bad)} asset broken / {visited_pages} fetched")
    return 1 if page_bad else 0


def _group(broken):
    by_target = {}
    for src, raw, path in broken:
        by_target.setdefault((raw, path), []).append(src)
    return by_target


def _print_group(by_target):
    for (raw, path), srcs in sorted(by_target.items()):
        print(f"  BROKEN  {raw}")
        print(f"          -> no file for {path}")
        shown = srcs[:6]
        for s in shown:
            print(f"          from {s}")
        if len(srcs) > len(shown):
            print(f"          ... and {len(srcs) - len(shown)} more page(s)")
        print()


def report_broken(page_broken, asset_broken, checked, n_pages):
    if asset_broken:
        by_asset = _group(asset_broken)
        print(f"\n{len(by_asset)} release-asset link(s) with no local file "
              f"(uploaded by CI after the skeleton build — not a page bug):")
        for (raw, path), _srcs in sorted(by_asset.items()):
            print(f"    {path}")
    if not page_broken:
        print(f"\nOK — all page/doc links resolve "
              f"({checked} internal links across {n_pages} pages checked).")
        return
    by_target = _group(page_broken)
    print(f"\n{len(page_broken)} broken page/doc link(s) "
          f"({len(by_target)} distinct target(s)) across {n_pages} pages:\n")
    _print_group(by_target)


def main():
    ap = argparse.ArgumentParser(description=__doc__,
                                 formatter_class=argparse.RawDescriptionHelpFormatter)
    ap.add_argument("target", nargs="?", default="doc/target/deploy",
                    help="deploy dir (local mode) or base URL with --live "
                         "(default: doc/target/deploy)")
    ap.add_argument("--live", action="store_true",
                    help="crawl the live site over HTTP instead of a local dir")
    args = ap.parse_args()

    if args.live:
        base = args.target if args.target.startswith("http") else "https://azul.rs"
        return check_live(base)
    return check_local(args.target)


if __name__ == "__main__":
    sys.exit(main())
